package com.example.dataproc;

import io.grpc.Status;
import io.grpc.stub.StreamObserver;

import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardOpenOption;
import java.util.UUID;
import java.util.concurrent.atomic.AtomicLong;

public class DataTransferServiceImpl extends DataTransferServiceGrpc.DataTransferServiceImplBase {
    private static final int DOWNLOAD_CHUNK_SIZE = 1024 * 1024;
    private final Path storageDir;

    public DataTransferServiceImpl(Path storageDir) {
        this.storageDir = storageDir;
    }

    @Override
    public StreamObserver<UploadRequest> upload(StreamObserver<UploadResponse> responseObserver) {
        return new StreamObserver<UploadRequest>() {
            private OutputStream outputStream;
            private String uploadId;
            private String fileName;
            private final AtomicLong bytesReceived = new AtomicLong();

            @Override
            public void onNext(UploadRequest request) {
                try {
                    if (uploadId == null || uploadId.isBlank()) {
                        uploadId = request.getUploadId().isBlank() ? UUID.randomUUID().toString() : request.getUploadId();
                    }
                    if (fileName == null || fileName.isBlank()) {
                        fileName = request.getFileName();
                        if (fileName == null || fileName.isBlank()) {
                            throw Status.INVALID_ARGUMENT.withDescription("file_name is required").asRuntimeException();
                        }
                        Path target = storageDir.resolve(Path.of(fileName).getFileName().toString());
                        Files.createDirectories(storageDir);
                        outputStream = Files.newOutputStream(
                                target,
                                StandardOpenOption.CREATE,
                                StandardOpenOption.TRUNCATE_EXISTING,
                                StandardOpenOption.WRITE
                        );
                    }
                    if (!request.getChunk().isEmpty()) {
                        byte[] data = request.getChunk().toByteArray();
                        outputStream.write(data);
                        bytesReceived.addAndGet(data.length);
                    }
                    if (request.getComplete()) {
                        closeQuietly(outputStream);
                        outputStream = null;
                    }
                } catch (Exception e) {
                    closeQuietly(outputStream);
                    responseObserver.onError(Status.INTERNAL.withDescription(e.getMessage()).withCause(e).asRuntimeException());
                }
            }

            @Override
            public void onError(Throwable t) {
                closeQuietly(outputStream);
            }

            @Override
            public void onCompleted() {
                closeQuietly(outputStream);
                UploadResponse response = UploadResponse.newBuilder()
                        .setUploadId(uploadId == null ? "" : uploadId)
                        .setBytesReceived(bytesReceived.get())
                        .setMessage("Upload completed")
                        .build();
                responseObserver.onNext(response);
                responseObserver.onCompleted();
            }
        };
    }

    @Override
    public void download(DownloadRequest request, StreamObserver<DownloadChunk> responseObserver) {
        Path source = storageDir.resolve(Path.of(request.getFileName()).getFileName().toString());
        if (!Files.exists(source)) {
            responseObserver.onError(Status.NOT_FOUND.withDescription("File not found").asRuntimeException());
            return;
        }
        try (InputStream in = Files.newInputStream(source, StandardOpenOption.READ)) {
            byte[] buffer = new byte[DOWNLOAD_CHUNK_SIZE];
            int read;
            while ((read = in.read(buffer)) != -1) {
                DownloadChunk chunk = DownloadChunk.newBuilder()
                        .setFileName(source.getFileName().toString())
                        .setChunk(com.google.protobuf.ByteString.copyFrom(buffer, 0, read))
                        .setComplete(false)
                        .build();
                responseObserver.onNext(chunk);
            }
            responseObserver.onNext(
                    DownloadChunk.newBuilder()
                            .setFileName(source.getFileName().toString())
                            .setComplete(true)
                            .build()
            );
            responseObserver.onCompleted();
        } catch (IOException e) {
            responseObserver.onError(Status.INTERNAL.withDescription(e.getMessage()).withCause(e).asRuntimeException());
        }
    }

    @Override
    public StreamObserver<TransferMessage> chat(StreamObserver<TransferMessage> responseObserver) {
        return new StreamObserver<TransferMessage>() {
            @Override
            public void onNext(TransferMessage message) {
                TransferMessage response = TransferMessage.newBuilder()
                        .setStreamId(message.getStreamId())
                        .setType(message.getType().isBlank() ? "ACK" : message.getType())
                        .setPayload(message.getPayload())
                        .putAllMetadata(message.getMetadataMap())
                        .build();
                responseObserver.onNext(response);
            }

            @Override
            public void onError(Throwable t) {
                responseObserver.onCompleted();
            }

            @Override
            public void onCompleted() {
                responseObserver.onCompleted();
            }
        };
    }

    private void closeQuietly(OutputStream outputStream) {
        if (outputStream != null) {
            try {
                outputStream.close();
            } catch (IOException ignored) {
            }
        }
    }
}

package com.example.dataproc;

import io.grpc.ManagedChannel;
import io.grpc.netty.shaded.io.grpc.netty.NettyChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class DataTransferClient {
    public static void main(String[] args) throws Exception {
        ManagedChannel channel = NettyChannelBuilder.forAddress("localhost", 50051)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();

        DataTransferServiceGrpc.DataTransferServiceStub asyncStub = DataTransferServiceGrpc.newStub(channel);

        CountDownLatch uploadDone = new CountDownLatch(1);
        StreamObserver<UploadResponse> uploadResponseObserver = new StreamObserver<>() {
            @Override
            public void onNext(UploadResponse value) {
                System.out.println("Upload bytes received: " + value.getBytesReceived());
            }

            @Override
            public void onError(Throwable t) {
                t.printStackTrace();
                uploadDone.countDown();
            }

            @Override
            public void onCompleted() {
                uploadDone.countDown();
            }
        };

        StreamObserver<UploadRequest> uploadObserver = asyncStub.upload(uploadResponseObserver);
        Path file = Paths.get("sample.bin");
        byte[] bytes = Files.readAllBytes(file);
        uploadObserver.onNext(
                UploadRequest.newBuilder()
                        .setUploadId("upload-1")
                        .setFileName(file.getFileName().toString())
                        .setChunk(com.google.protobuf.ByteString.copyFrom(bytes))
                        .setComplete(true)
                        .build()
        );
        uploadObserver.onCompleted();
        uploadDone.await(1, TimeUnit.MINUTES);

        CountDownLatch chatDone = new CountDownLatch(1);
        StreamObserver<TransferMessage> chatResponseObserver = new StreamObserver<>() {
            @Override
            public void onNext(TransferMessage value) {
                System.out.println("Received chat response type: " + value.getType());
            }

            @Override
            public void onError(Throwable t) {
                t.printStackTrace();
                chatDone.countDown();
            }

            @Override
            public void onCompleted() {
                chatDone.countDown();
            }
        };

        StreamObserver<TransferMessage> chatObserver = asyncStub.chat(chatResponseObserver);
        chatObserver.onNext(
                TransferMessage.newBuilder()
                        .setStreamId("stream-1")
                        .setType("DATA")
                        .setPayload(com.google.protobuf.ByteString.copyFromUtf8("hello"))
                        .putMetadata("source", "client")
                        .build()
        );
        chatObserver.onCompleted();
        chatDone.await(1, TimeUnit.MINUTES);

        channel.shutdownNow().awaitTermination(5, TimeUnit.SECONDS);
    }
}